    labs(
      title = "Daily Returns: S&P 500 vs Bitcoin",
      x = "Date",
      y = "Return"
    ) +
    theme_minimal()
  print(p)

  # Clean up intermediate objects that are no longer needed
  rm(merged_data, envir = .GlobalEnv)
})

